using System.Linq;using System.Windows;using System.Windows.Controls;using System.Windows.Input;using КулинарнаяКнига.ApplicationData;using КулинарнаяКнига.AppData;
namespace КулинарнаяКнига.Pages{public partial class RecipesPage:Page{public RecipesPage(){InitializeComponent();Loaded+=L;}void L(object s,RoutedEventArgs e){cmbCategory.Items.Add("Все категории");foreach(var c in AppConnect.model01.Categories.ToList())cmbCategory.Items.Add(c.CategoryName);cmbCategory.SelectedIndex=0;cmbSort.ItemsSource=new[]{"Без сортировки","По возрастанию времени","По убыванию времени"};cmbSort.SelectedIndex=0;Apply();}
Recipes[] GetFilteredRecipes(){var q=AppConnect.model01.Recipes.ToList().AsQueryable();if(cmbCategory.SelectedIndex>0){var cat=cmbCategory.SelectedItem.ToString();q=q.Where(r=>r.Category!=null&&r.Category.CategoryName==cat);}var s=tbSearch.Text?.ToLower()??"";if(!string.IsNullOrWhiteSpace(s))q=q.Where(r=>(r.RecipeName??"").ToLower().Contains(s)||(r.Description??"").ToLower().Contains(s)||(r.Category!=null&&(r.Category.CategoryName??"").ToLower().Contains(s)));if(cmbSort.SelectedIndex==1)q=q.OrderBy(r=>r.CookingTime);if(cmbSort.SelectedIndex==2)q=q.OrderByDescending(r=>r.CookingTime);return q.ToArray();}
void Apply(){var arr=GetFilteredRecipes();lvRecipes.ItemsSource=arr;icRecipes.ItemsSource=arr;tbCount.Text=$"Найдено: {arr.Length}";}void FilterChanged(object s,RoutedEventArgs e)=>Apply();void ShowList_Click(object s,RoutedEventArgs e){lvRecipes.Visibility=Visibility.Visible;icRecipes.Visibility=Visibility.Collapsed;}void ShowTiles_Click(object s,RoutedEventArgs e){lvRecipes.Visibility=Visibility.Collapsed;icRecipes.Visibility=Visibility.Visible;}void Add_Click(object s,RoutedEventArgs e){NavigationService?.Navigate(new AddEditRecipePage(null));}void Fav_Click(object s,RoutedEventArgs e){NavigationService?.Navigate(new FavoritesPage());}void lvRecipes_MouseDoubleClick(object s,MouseButtonEventArgs e){if(lvRecipes.SelectedItem is Recipes r)NavigationService?.Navigate(new AddEditRecipePage(r));}}}
